pub struct RunGraphContinuationBinding {
    pub run_id: String,
    pub task_id: String,
    pub status: String,
    pub active_bounded_unit: serde_json::Value,
    pub binding_source: String,
    pub why_this_unit: String,
    pub primary_path: String,
    pub sequential_vs_parallel_posture: String,
    pub request_text: Option<String>,
    pub recorded_at: String,
}

impl RunGraphContinuationBinding {
    pub(crate) fn validate(&self) -> Result<(), StateStoreError> {
        if self.run_id.trim().is_empty() {
            return Err(StateStoreError::InvalidTaskRecord {
                reason: "run-graph continuation binding run_id must be non-empty".to_string(),
            });
        }
        if self.task_id.trim().is_empty() {
            return Err(StateStoreError::InvalidTaskRecord {
                reason: format!(
                    "run-graph continuation binding for `{}` must have non-empty task_id",
                    self.run_id
                ),
            });
        }
        if self.status != "bound" {
            return Err(StateStoreError::InvalidTaskRecord {
                reason: format!(
                    "run-graph continuation binding for `{}` must have status `bound`, got `{}`",
                    self.run_id, self.status
                ),
            });
        }
        if !self.active_bounded_unit.is_object() {
            return Err(StateStoreError::InvalidTaskRecord {
                reason: format!(
                    "run-graph continuation binding for `{}` must have object active_bounded_unit",
                    self.run_id
                ),
            });
        }
        for (field, value) in [
            ("binding_source", self.binding_source.as_str()),
            ("why_this_unit", self.why_this_unit.as_str()),
            ("primary_path", self.primary_path.as_str()),
            (
                "sequential_vs_parallel_posture",
                self.sequential_vs_parallel_posture.as_str(),
            ),
            ("recorded_at", self.recorded_at.as_str()),
        ] {
            if value.trim().is_empty() {
                return Err(StateStoreError::InvalidTaskRecord {
                    reason: format!(
                        "run-graph continuation binding for `{}` has empty field `{field}`",
                        self.run_id
                    ),

                )
        });
    let continuation_binding =
        crate::continuation_binding_summary::build_continuation_binding_summary(
            explicit_continuation_binding.as_ref(),
            Some(&status),
            latest_run_graph_recovery.as_ref(),
            latest_run_graph_dispatch_receipt.as_ref(),
            continuation_binding_evidence_ambiguous,
        );
    if continuation_binding["status"] != "bound" {
        return Err(format!(
            "Latest continuation binding for run `{}` is ambiguous. Either bind the next bounded unit explicitly with `vida taskflow continuation bind {} --task-id <task-id> --json` or pass `--run-id {}` to refresh that specific run.",
            status.run_id, status.run_id, status.run_id
        ));
    }
    if status.status == "completed"
        && continuation_binding["active_bounded_unit"]["kind"] != "downstream_dispatch_target"
    {
        let unit_kind = continuation_binding["active_bounded_unit"]["kind"]
            .as_str()
            .unwrap_or("unknown");
        return Err(format!(
            "Latest continuation binding for run `{}` points to `{unit_kind}`, which is not resumeable through default `vida taskflow consume continue --json`. Pass `--run-id {}` to refresh the completed run explicitly or bind/shape the next bounded unit before continuing.",
            status.run_id, status.run_id
        ));
    }
    Ok(status.run_id)
}

